exportgraphics(fig, PictureFolder + filesep + "Time in service histogram.svg"); %[output:18fd4a02]
%%
%[text] Compare simulation values to theoretical values
%L = count of customers in the system
L_diff = (L-meanNumInSystem)/L * 100 %[output:1d02a17b]

%Lq = count of customers waiting
Lq_diff = (Lq-meanNumWaiting)/Lq * 100 %[output:36837a14]

%W = total time in system
W_diff = (W-meanTimeInSystem)/W *100 %[output:2099d11d]

%Wq = total time in queue
Wq_diff = (Wq-meanTimeInQueue)/Wq *100 %[output:05022d09]

